import React, { useState, useEffect } from "react";
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [templateName, setTemplateName] = useState("promo");
  const [htmlContent, setHtmlContent] = useState("");
  const [resultMsg, setResultMsg] = useState(null);

  // ===========================
  // 📌 CÁC TEMPLATE CÓ SẴN
  // ===========================
  const templates = {
    promo: `
      <h2>🎉 Ưu đãi đặc biệt!</h2>
      <p>Giảm 20% tất cả sản phẩm tuần này!</p>
    `,
    holiday: `
      <h2>🌸 Quà tặng ngày lễ!</h2>
      <p>Hoa tươi giảm giá cho các dịp lễ hội.</p>
    `,
    custom: ""
  };

  // ===========================
  // 📌 LOAD TEMPLATE
  // ===========================
  useEffect(() => {
    if (templateName !== "custom") {
      setHtmlContent(templates[templateName]);
    }
  }, [templateName]);


  // ===========================
  // 📌 GỬI EMAIL
  // ===========================
  const sendEmail = async () => {
    setResultMsg(null);

    if (!subject.trim()) {
      setResultMsg({ type: "error", text: "❌ Bạn phải nhập tiêu đề email!" });
      return;
    }

    if (!htmlContent.trim()) {
      setResultMsg({ type: "error", text: "❌ Nội dung email không được trống!" });
      return;
    }

    try {
      const token = localStorage.getItem("token");

      const res = await axios.post(
        `${API_URL}/api/email/send`,
        {
          subject,
          group,
          html: htmlContent,
          templateName
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      setResultMsg({ type: "success", text: res.data.message });

    } catch (err) {
      console.error("Frontend Email Error:", err);

      setResultMsg({
        type: "error",
        text: "❌ Không thể gửi email (frontend error). Kiểm tra backend console!"
      });
    }
  };


  return (
    <div style={{ maxWidth: "900px", margin: "0 auto", padding: "40px" }}>
      <h1 style={{ fontSize: "28px", fontWeight: "700", color: "#d14b6a" }}>
        📩 Gửi Email Marketing
      </h1>

      <div style={{
        background: "white",
        padding: "25px",
        borderRadius: "12px",
        boxShadow: "0 10px 40px rgba(0,0,0,0.05)",
        marginTop: "20px"
      }}>
        {/* SUBJECT */}
        <label>Tiêu đề Email</label>
        <input
          type="text"
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
          placeholder="Nhập tiêu đề..."
          style={{ width: "100%", marginTop: "8px", marginBottom: "20px", padding: "12px" }}
        />

        {/* GROUP */}
        <label>Gửi đến nhóm</label>
        <select
          value={group}
          onChange={(e) => setGroup(e.target.value)}
          style={{ width: "100%", padding: "12px", marginBottom: "20px" }}
        >
          <option value="all">📢 Tất cả khách hàng</option>
          <option value="user">👤 Chỉ User bình thường</option>
          <option value="admin">🛠 Admin</option>
          <option value="newsletter">📬 Người đăng ký Newsletter</option>
          <option value="vip">💎 VIP (Chi ≥ 3.000.000)</option>
        </select>

        {/* TEMPLATE */}
        <label>Mẫu email</label>
        <select
          value={templateName}
          onChange={(e) => setTemplateName(e.target.value)}
          style={{ width: "100%", padding: "12px", marginBottom: "20px" }}
        >
          <option value="promo">🎁 Khuyến mãi</option>
          <option value="holiday">🎉 Dịp lễ</option>
          <option value="custom">📝 Tuỳ chỉnh</option>
        </select>

        {/* CUSTOM HTML */}
        {templateName === "custom" && (
          <>
            <label>Nội dung HTML</label>
            <textarea
              rows="6"
              value={htmlContent}
              onChange={(e) => setHtmlContent(e.target.value)}
              placeholder="Nhập nội dung HTML..."
              style={{ width: "100%", padding: "12px", marginBottom: "20px" }}
            />
          </>
        )}

        {/* BUTTON */}
        <button
          onClick={sendEmail}
          style={{
            width: "100%",
            background: "#d86b7a",
            padding: "15px",
            borderRadius: "8px",
            color: "white",
            fontWeight: "bold",
            fontSize: "16px",
            cursor: "pointer"
          }}
        >
          ✉ Gửi Email
        </button>

        {/* RESULT MESSAGE */}
        {resultMsg && (
          <div
            style={{
              marginTop: "20px",
              padding: "15px",
              borderRadius: "8px",
              background: resultMsg.type === "success" ? "#e8fff0" : "#ffe8e8",
              color: resultMsg.type === "success" ? "#008f3c" : "#d10000"
            }}
          >
            {resultMsg.text}
          </div>
        )}
      </div>

      {/* PREVIEW */}
      <div style={{ marginTop: "40px" }}>
        <h2>🔍 Preview</h2>
        <div
          style={{
            background: "white",
            padding: "25px",
            borderRadius: "12px",
            border: "1px solid #eee"
          }}
          dangerouslySetInnerHTML={{ __html: htmlContent }}
        />
      </div>
    </div>
  );
};

export default SendEmailPage;
